// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{})
}

// ServeMux is an abstraction of http.ServeMux.
type ServeMux interface {
	HandleFunc(pattern string, handler func(http.ResponseWriter, *http.Request))
	ServeHTTP(w http.ResponseWriter, r *http.Request)
}

type StdHTTPServerOptions struct {
	BaseURL          string
	BaseRouter       ServeMux
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, m ServeMux) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseRouter: m,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, m ServeMux, baseURL string) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseURL:    baseURL,
		BaseRouter: m,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options StdHTTPServerOptions) http.Handler {
	m := options.BaseRouter

	if m == nil {
		m = http.NewServeMux()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	m.HandleFunc("POST "+options.BaseURL+"/api/announce", wrapper.PostAnnounce)
	m.HandleFunc("GET "+options.BaseURL+"/api/check", wrapper.GetCheck)
	m.HandleFunc("POST "+options.BaseURL+"/api/listen", wrapper.PostListen)
	m.HandleFunc("POST "+options.BaseURL+"/api/register", wrapper.PostRegister)
	m.HandleFunc("POST "+options.BaseURL+"/api/release", wrapper.PostRelease)
	m.HandleFunc("GET "+options.BaseURL+"/api/resolve", wrapper.GetResolve)
	m.HandleFunc("POST "+options.BaseURL+"/api/send", wrapper.PostSend)
	m.HandleFunc("DELETE "+options.BaseURL+"/api/session/{callsign}", wrapper.DeleteSession)
	m.HandleFunc("GET "+options.BaseURL+"/api/sessions", wrapper.GetSessions)
	m.HandleFunc("GET "+options.BaseURL+"/api/sessions/bash-dump", wrapper.GetSessionsBashDump)
	m.HandleFunc("POST "+options.BaseURL+"/api/sessions/edit", wrapper.PostEditSession)
	m.HandleFunc("POST "+options.BaseURL+"/api/sessions/export", wrapper.PostSessionsExport)
	m.HandleFunc("GET "+options.BaseURL+"/api/sessions/find", wrapper.GetSessionsFind)
	m.HandleFunc("GET "+options.BaseURL+"/api/sessions/heatmap", wrapper.GetSessionsHeatmap)
	m.HandleFunc("DELETE "+options.BaseURL+"/api/sessions/{identifier}", wrapper.DeleteSessionById)
	m.HandleFunc("GET "+options.BaseURL+"/api/sessions/{identifier}/detail", wrapper.GetSessionDetail)
	m.HandleFunc("POST "+options.BaseURL+"/api/sessions/{identifier}/export", wrapper.PostSessionExport)
	m.HandleFunc("GET "+options.BaseURL+"/api/sessions/{identifier}/messages", wrapper.GetSessionMessages)
	m.HandleFunc("GET "+options.BaseURL+"/api/sessions/{identifier}/peek", wrapper.GetSessionPeek)
	m.HandleFunc("GET "+options.BaseURL+"/api/sessions/{identifier}/tool-context", wrapper.GetSessionToolContext)
	m.HandleFunc("GET "+options.BaseURL+"/api/sessions/{identifier}/tools", wrapper.GetSessionTools)
	m.HandleFunc("POST "+options.BaseURL+"/api/sweep", wrapper.PostSweep)
	m.HandleFunc("GET "+options.BaseURL+"/api/timeline", wrapper.GetTimeline)
	m.HandleFunc("GET "+options.BaseURL+"/api/usage", wrapper.GetUsage)
	m.HandleFunc("GET "+options.BaseURL+"/api/wait", wrapper.GetWait)

	return m
}

